@namespace sv_346047b6897d4bb5b8502568e08dc133.Components.Pages.Apply

<div class="step-indicator">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var css = step == CurrentStep ? "step active"
                : CompletedSteps.Contains(step) ? "step completed"
                : "step dimmed";

        <div class="@css" @onclick="() => OnStepClick(step)">
            <span class="step-number">
                @if (CompletedSteps.Contains(step))
                {
                    <span>&#10003;</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </div>

        @if (step < StepNames.Length - 1)
        {
            <div class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></div>
        }
    }
</div>

@code {
    private static readonly string[] StepNames =
        { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    flex-wrap: wrap;
    gap: 0.25rem;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.25rem;
    padding: 0.5rem;
    min-width: 80px;
}

.step.completed {
    cursor: pointer;
    color: #198754;
}

.step.active .step-number {
    background-color: #0d6efd;
    color: white;
}

.step.completed .step-number {
    background-color: #198754;
    color: white;
}

.step.dimmed {
    opacity: 0.5;
}

.step-number {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid #dee2e6;
    font-weight: bold;
    font-size: 0.85rem;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
}

.step-connector {
    width: 30px;
    height: 2px;
    background-color: #dee2e6;
    align-self: center;
    margin-bottom: 1.25rem;
}

.step-connector.completed {
    background-color: #198754;
}

@namespace sv_346047b6897d4bb5b8502568e08dc133.Components.Pages.Apply
@using sv_346047b6897d4bb5b8502568e08dc133.Services

<div class="personal-info-step">
    <h4>Personal Information</h4>

    <div class="mb-3">
        <label class="form-label">Full Name *</label>
        <input type="text" class="form-control" @bind="FullName" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email *</label>
        <input type="email" class="form-control" @bind="Email" @bind:event="oninput" />
        @if (!string.IsNullOrEmpty(_emailError))
        {
            <div class="text-danger small mt-1">@_emailError</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone *</label>
        <input type="tel" class="form-control" @bind="Phone" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Address *</label>
        <textarea class="form-control" rows="2" @bind="Address" @bind:event="oninput"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <div class="alert alert-danger">@_validationError</div>
    }

    <div class="d-flex justify-content-end">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@_isValidating">
            @if (_isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Next
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<(string FullName, string Email, string Phone, string Address)> OnNext { get; set; }

    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private string _validationError = "";
    private string _emailError = "";
    private bool _isValidating;

    private async Task HandleNext()
    {
        _validationError = "";
        _emailError = "";

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            _validationError = "All fields are required.";
            return;
        }

        _isValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!emailValid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync((FullName, Email, Phone, Address));
        }
        finally
        {
            _isValidating = false;
        }
    }
}

@namespace sv_346047b6897d4bb5b8502568e08dc133.Components.Pages.Apply

<div class="work-entry-form card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            }
        </div>

        <div class="row mb-2">
            <div class="col-md-6">
                <label class="form-label">Company *</label>
                <input type="text" class="form-control" value="@Entry.Company"
                       @onchange="e => Update(Entry with { Company = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title *</label>
                <input type="text" class="form-control" value="@Entry.Title"
                       @onchange="e => Update(Entry with { Title = (string?)e.Value ?? "" })" />
            </div>
        </div>

        <div class="row mb-2">
            <div class="col-md-4">
                <label class="form-label">Start Date *</label>
                <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@Entry.EndDate?.ToString("yyyy-MM-dd")"
                       disabled="@_isCurrent"
                       @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" checked="@_isCurrent"
