<div class="step-indicator">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var css = step == CurrentStep ? "step active"
                : CompletedSteps.Contains(step) ? "step completed"
                : "step dimmed";

        <div class="@css" @onclick="() => OnStepClick(step)">
            <span class="step-number">
                @if (CompletedSteps.Contains(step))
                {
                    <span>&#10003;</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </div>

        @if (step < StepNames.Length - 1)
        {
            <div class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></div>
        }
    }
</div>

@code {
    private static readonly string[] StepNames =
        { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    flex-wrap: wrap;
    gap: 0.25rem;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.25rem;
    padding: 0.5rem;
    min-width: 80px;
}

.step.completed {
    cursor: pointer;
    color: #198754;
}

.step.active .step-number {
    background-color: #0d6efd;
    color: white;
}

.step.completed .step-number {
    background-color: #198754;
    color: white;
}

.step.dimmed {
    opacity: 0.5;
}

.step-number {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid #dee2e6;
    font-weight: bold;
    font-size: 0.85rem;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
}

.step-connector {
    width: 30px;
    height: 2px;
    background-color: #dee2e6;
    align-self: center;
    margin-bottom: 1.25rem;
}

.step-connector.completed {
    background-color: #198754;
}

