            <span class="step-label">@StepNames[step]</span>
        </div>

        @if (step < StepNames.Length - 1)
        {
            <div class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></div>
        }
    }
</div>

@code {
