<div class="personal-info-step">
    <h4>Personal Information</h4>

    <div class="mb-3">
        <label class="form-label">Full Name *</label>
        <input type="text" class="form-control" @bind="FullName" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email *</label>
        <input type="email" class="form-control" @bind="Email" @bind:event="oninput" />
        @if (!string.IsNullOrEmpty(_emailError))
        {
            <div class="text-danger small mt-1">@_emailError</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone *</label>
        <input type="tel" class="form-control" @bind="Phone" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Address *</label>
        <textarea class="form-control" rows="2" @bind="Address" @bind:event="oninput"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <div class="alert alert-danger">@_validationError</div>
    }

    <div class="d-flex justify-content-end">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@_isValidating">
            @if (_isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Next
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<(string FullName, string Email, string Phone, string Address)> OnNext { get; set; }

    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private string _validationError = "";
    private string _emailError = "";
    private bool _isValidating;

    private async Task HandleNext()
    {
        _validationError = "";
        _emailError = "";

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            _validationError = "All fields are required.";
            return;
        }

        _isValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!emailValid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync((FullName, Email, Phone, Address));
        }
        finally
        {
            _isValidating = false;
        }
    }
}
