<div class="references-step">
    <h4>References</h4>
    <p class="text-muted">Please provide 2-3 professional references.</p>

    @for (int i = 0; i < _references.Count; i++)
    {
        var index = i;
        <ReferenceForm Entry="_references[index]" Index="index"
                       CanRemove="_references.Count > 2"
                       OnChanged="e => HandleChanged(index, e)"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (_references.Count < 3)
    {
        <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
            + Add Reference
        </button>
    }

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <div class="alert alert-danger">@_validationError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<ReferenceForm.ReferenceModel>? InitialReferences { get; set; }
    [Parameter] public EventCallback<List<ReferenceForm.ReferenceModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<ReferenceForm.ReferenceModel> _references = new();
    private string _validationError = "";

    protected override void OnInitialized()
    {
        if (InitialReferences is { Count: > 0 })
        {
            _references = InitialReferences;
        }
        else
        {
            _references = new List<ReferenceForm.ReferenceModel> { new(), new() };
        }
    }

    private void AddReference()
    {
        if (_references.Count < 3)
        {
            _references.Add(new ReferenceForm.ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (_references.Count > 2)
        {
            _references.RemoveAt(index);
        }
    }

    private void HandleChanged(int index, ReferenceForm.ReferenceModel updated)
    {
        _references[index] = updated;
    }

    private async Task HandleNext()
    {
        _validationError = "";

        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _validationError = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync(_references);
    }
}
