.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    flex-wrap: wrap;
    gap: 0.25rem;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.25rem;
    padding: 0.5rem;
    min-width: 80px;
}

.step.completed {
    cursor: pointer;
    color: #198754;
}

.step.active .step-number {
    background-color: #0d6efd;
    color: white;
}

.step.completed .step-number {
    background-color: #198754;
    color: white;
}

.step.dimmed {
    opacity: 0.5;
}

.step-number {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid #dee2e6;
    font-weight: bold;
    font-size: 0.85rem;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
}

.step-connector {
    width: 30px;
    height: 2px;
    background-color: #dee2e6;
    align-self: center;
    margin-bottom: 1.25rem;
}

.step-connector.completed {
    background-color: #198754;
}

