@namespace sv_346047b6897d4bb5b8502568e08dc133.Components.Pages.Apply

<div class="work-entry-form card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            }
        </div>

        <div class="row mb-2">
            <div class="col-md-6">
                <label class="form-label">Company *</label>
                <input type="text" class="form-control" value="@Entry.Company"
                       @onchange="e => Update(Entry with { Company = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title *</label>
                <input type="text" class="form-control" value="@Entry.Title"
                       @onchange="e => Update(Entry with { Title = (string?)e.Value ?? "" })" />
            </div>
        </div>

        <div class="row mb-2">
            <div class="col-md-4">
                <label class="form-label">Start Date *</label>
                <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@Entry.EndDate?.ToString("yyyy-MM-dd")"
                       disabled="@_isCurrent"
                       @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" checked="@_isCurrent"
                           @onchange="HandleCurrentChanged" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
        </div>

        <div class="mb-2">
            <label class="form-label">Description</label>
            <textarea class="form-control" rows="2" value="@Entry.Description"
                      @onchange="e => Update(Entry with { Description = (string?)e.Value ?? "" })"></textarea>
        </div>
    </div>
</div>

@code {
    [Parameter] public WorkEntryModel Entry { get; set; } = new();
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryModel> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool _isCurrent;

    protected override void OnParametersSet()
    {
        _isCurrent = Entry.EndDate == null && Entry.IsCurrent;
    }

    private void HandleCurrentChanged(ChangeEventArgs e)
    {
        _isCurrent = (bool)(e.Value ?? false);
        var updated = Entry with { IsCurrent = _isCurrent, EndDate = _isCurrent ? null : Entry.EndDate };
        Update(updated);
    }

    private void Update(WorkEntryModel updated)
    {
        OnChanged.InvokeAsync(updated);
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }
}

@namespace sv_346047b6897d4bb5b8502568e08dc133.Components.Pages.Apply

<div class="work-history-step">
    <h4>Work History</h4>

    @for (int i = 0; i < _entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="_entries[index]" Index="index"
                       CanRemove="_entries.Count > 1"
                       OnChanged="e => HandleEntryChanged(index, e)"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <div class="alert alert-danger">@_validationError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryForm.WorkEntryModel>? InitialEntries { get; set; }
    [Parameter] public EventCallback<List<WorkEntryForm.WorkEntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<WorkEntryForm.WorkEntryModel> _entries = new();
    private string _validationError = "";

    protected override void OnInitialized()
    {
        if (InitialEntries is { Count: > 0 })
        {
            _entries = InitialEntries;
        }
        else
        {
            _entries = new List<WorkEntryForm.WorkEntryModel> { new() };
        }
    }

    private void AddEntry()
    {
        _entries.Add(new WorkEntryForm.WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (_entries.Count > 1)
        {
            _entries.RemoveAt(index);
        }
    }

    private void HandleEntryChanged(int index, WorkEntryForm.WorkEntryModel updated)
    {
        _entries[index] = updated;
    }

    private async Task HandleNext()
    {
        _validationError = "";

        foreach (var entry in _entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                _validationError = "Company and Job Title are required for all entries.";
                return;
            }
        }

        await OnNext.InvokeAsync(_entries);
    }
}

