@namespace sv_346047b6897d4bb5b8502568e08dc133.Components.Pages.Apply

<div class="cover-letter-step">
    <h4>Cover Letter</h4>

    <div class="mb-3">
        <textarea class="form-control" rows="12" @bind="CoverLetter" @bind:event="oninput"
                  maxlength="2000" placeholder="Write your cover letter here..."></textarea>
        <div class="text-muted small mt-1 text-end">
            @(CoverLetter?.Length ?? 0) / 2000 characters
        </div>
    </div>

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <div class="alert alert-danger">@_validationError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string _validationError = "";

    private async Task HandleNext()
    {
        _validationError = "";

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            _validationError = "Please write a cover letter.";
            return;
        }

        await OnNext.InvokeAsync(CoverLetter);
    }
}

