@namespace sv_346047b6897d4bb5b8502568e08dc133.Components.Pages.Apply

<div class="review-step">
    <h4>Review & Submit</h4>
    <p class="text-muted">Please review your application before submitting.</p>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="#" @onclick="() => OnEditStep.InvokeAsync(0)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <p><strong>Name:</strong> @FullName</p>
            <p><strong>Email:</strong> @Email</p>
            <p><strong>Phone:</strong> @Phone</p>
            <p class="mb-0"><strong>Address:</strong> @Address</p>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <a href="#" @onclick="() => OnEditStep.InvokeAsync(1)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @if (WorkEntries != null)
            {
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 pb-2 border-bottom">
                        <p class="mb-1"><strong>@entry.Title</strong> at @entry.Company</p>
                        <p class="mb-1 small text-muted">
                            @entry.StartDate.ToString("MMM yyyy") &ndash;
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                        </p>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 small">@entry.Description</p>
                        }
                    </div>
                }
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="#" @onclick="() => OnEditStep.InvokeAsync(2)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @if (References != null)
            {
                @foreach (var r in References)
                {
                    <div class="mb-2 pb-2 border-bottom">
                        <p class="mb-1"><strong>@r.Name</strong> (@r.Relationship)</p>
                        <p class="mb-0 small">@r.Email &bull; @r.Phone</p>
                    </div>
                }
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <a href="#" @onclick="() => OnEditStep.InvokeAsync(3)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-success btn-lg" @onclick="() => OnSubmit.InvokeAsync()" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryForm.WorkEntryModel>? WorkEntries { get; set; }
    [Parameter] public List<ReferenceForm.ReferenceModel>? References { get; set; }
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
}

