@page "/apply"
@using sv_346047b6897d4bb5b8502568e08dc133.Components.Pages.Apply
@using sv_346047b6897d4bb5b8502568e08dc133.Models
@using sv_346047b6897d4bb5b8502568e08dc133.Services
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    @if (_submitted)
    {
        <div class="alert alert-success text-center">
            <h4>Application Submitted!</h4>
            <p>Your application has been received. Your application ID is:</p>
            <p class="fs-3 fw-bold">@_applicationId</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep" CompletedSteps="_completedSteps"
                       OnStepClicked="GoToStep" />

        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                  OnNext="HandlePersonalNext" />
                break;
            case 1:
                <WorkHistoryStep InitialEntries="_workEntries" OnNext="HandleWorkNext" OnBack="GoBack" />
                break;
            case 2:
                <ReferencesStep InitialReferences="_references" OnNext="HandleReferencesNext" OnBack="GoBack" />
                break;
            case 3:
                <CoverLetterStep CoverLetter="@_coverLetter" OnNext="HandleCoverLetterNext" OnBack="GoBack" />
                break;
            case 4:
                <ReviewStep FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                            WorkEntries="_workEntries" References="_references" CoverLetter="@_coverLetter"
                            IsSubmitting="_isSubmitting"
                            OnEditStep="GoToStep" OnBack="GoBack" OnSubmit="HandleSubmit" />
                break;
        }
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int _currentStep;
    private HashSet<int> _completedSteps = new();

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryForm.WorkEntryModel> _workEntries = new();

    // Step 3
    private List<ReferenceForm.ReferenceModel> _references = new();

    // Step 4
    private string _coverLetter = "";

    // Submission
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;

    private void HandlePersonalNext((string FullName, string Email, string Phone, string Address) data)
    {
        _fullName = data.FullName;
        _email = data.Email;
        _phone = data.Phone;
        _address = data.Address;
        CompleteAndAdvance(0);
    }

    private void HandleWorkNext(List<WorkEntryForm.WorkEntryModel> entries)
    {
        _workEntries = entries;
        CompleteAndAdvance(1);
    }

    private void HandleReferencesNext(List<ReferenceForm.ReferenceModel> refs)
    {
        _references = refs;
        CompleteAndAdvance(2);
    }

    private void HandleCoverLetterNext(string coverLetter)
    {
        _coverLetter = coverLetter;
        CompleteAndAdvance(3);
    }

    private async Task HandleSubmit()
    {
        _isSubmitting = true;
        try
        {
            var workHistory = new WorkHistory(
                _workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate, e.EndDate, e.Description
                )).ToList()
            );

            var references = _references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)
            ).ToList();

            var application = new JobApplication(
                new PersonalInfo(_fullName, _email, _phone, _address),
                workHistory,
                references,
                _coverLetter
            );

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private void CompleteAndAdvance(int step)
    {
        _completedSteps.Add(step);
        _currentStep = step + 1;
    }

    private void GoToStep(int step)
    {
        _currentStep = step;
    }

    private void GoBack()
    {
        if (_currentStep > 0)
            _currentStep--;
    }
}

